export class GitHubRepoSecretWriter {
    owner;
    repo;
    constructor(githubToken) {
        const repoSlug = process.env.GITHUB_REPOSITORY;
        if (!repoSlug) {
            throw new Error('GITHUB_REPOSITORY is required for bootstrap mode.');
        }
        const [owner, repo] = repoSlug.split('/');
        if (!owner || !repo) {
            throw new Error('GITHUB_REPOSITORY must be in owner/repo form.');
        }
        this.owner = owner;
        this.repo = repo;
        this.githubToken = githubToken;
    }
    githubToken;
    async secretExists(name) {
        const response = await fetch(`https://api.github.com/repos/${encodeURIComponent(this.owner)}/${encodeURIComponent(this.repo)}/actions/secrets/${encodeURIComponent(name)}`, {
            headers: {
                accept: 'application/vnd.github+json',
                authorization: `Bearer ${this.githubToken}`,
                'x-github-api-version': '2022-11-28'
            }
        });
        if (response.ok) {
            return true;
        }
        if (response.status === 404) {
            return false;
        }
        throw new Error(`GitHub secret lookup failed with status ${response.status}.`);
    }
    async writeSecret(name, value) {
        if (!name.trim() || !value.trim()) {
            throw new Error('secret name and value are required');
        }
        throw new Error('GitHub secret writing is blocked until bootstrap depends on the published crypto package.');
    }
}
